<?php $__env->startSection('content'); ?><section class="hero"><h1><?php echo e($game->name); ?></h1><p><?php echo e($game->description); ?></p></section><form method="post" action="<?php echo e(route('order.store')); ?>" class="two"><?php echo csrf_field(); ?><div class="card"><h2>Select Package</h2><div class="packages"><?php $__currentLoopData = $packages; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $package): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><label class="package"><input type="radio" name="game_package_id" value="<?php echo e($package->id); ?>" required><span class="package-box"><span class="package-title"><?php echo e($package->name); ?></span><br><span class="muted"><?php echo e($package->credit_label); ?></span><br><span class="price">₹<?php echo e(number_format($package->price_minor/100,2)); ?></span></span></label><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></div></div><div class="card"><h2>Player Details</h2><label>Player ID / UID</label><input name="player_id" value="<?php echo e(old('player_id')); ?>" required><br><br><?php if($game->requires_server_id): ?><label>Server ID</label><input name="server_id" value="<?php echo e(old('server_id')); ?>" required><br><br><?php endif; ?><label>Payment Method</label><div class="pay-options"><label class="package"><input type="radio" name="payment_mode" value="wallet" required><span class="package-box">Wallet</span></label><label class="package"><input type="radio" name="payment_mode" value="online" required><span class="package-box">Razorpay Online</span></label></div><br><button class="btn" style="width:100%">Purchase Now</button></div></form><?php $__env->stopSection(); ?>

